// ── Internal helpers (deterministic, no state mutation) ────────────────────

function m11DerivePhase(tick: number): RunPhase {
  const t = clamp(tick, 0, RUN_TOTAL_TICKS - 1);
  const third = RUN_TOTAL_TICKS / 3;
  if (t < third) return 'EARLY';
  if (t < third * 2) return 'MID';
  return 'LATE';
}

function m11DeriveRegime(tick: number, schedule: MacroEvent[]): MacroRegime {
  // buildMacroSchedule uses random ticks; normalize to deterministic order.
  const sorted = [...(schedule ?? [])].sort((a, b) => a.tick - b.tick);
  let regime: MacroRegime = 'NEUTRAL';
  for (const ev of sorted) {
    if (ev.tick > tick) break;
    if (ev.regimeChange) regime = ev.regimeChange;
  }
  return regime;
}

function m11InChaosWindow(tick: number, windows: ChaosWindow[]): boolean {
  for (const w of windows ?? []) {
    if (tick >= w.startTick && tick <= w.endTick) return true;
  }
  return false;
}

// ── Exec hook ─────────────────────────────────────────────────────────────

/**
 * missedOpportunityStreakTax
 *
 * Called by MechanicsRouter inside the EngineOrchestrator tick or card handler.
 * All state mutations MUST be returned in the output — never applied in place.
 * All telemetry MUST be emitted via the emit callback.
 *
 * @param input  Typed input snapshot
 * @param emit   Telemetry emitter — call for every meaningful state change
 * @returns      Typed output (all fields populated, no throws)
 */
export function missedOpportunityStreakTax(input: M11Input, emit: MechanicEmitter): M11Output {
  const stateMissedOpportunityCount = (input.stateMissedOpportunityCount as number) ?? 0;
  const stateTick = clamp(((input.stateTick as number) ?? 0), 0, RUN_TOTAL_TICKS - 1);
  const statePressureTier = (input.statePressureTier as PressureTier) ?? 'LOW';

  // Deterministic “context” (used for telemetry/debug + keeps shared imports live)
  const seed = computeHash(`M11:${stateTick}:${stateMissedOpportunityCount}:${statePressureTier}`);
  const macroSchedule = buildMacroSchedule(seed, MACRO_EVENTS_PER_RUN);
  const chaosWindows = buildChaosWindows(seed, CHAOS_WINDOWS_PER_RUN);

  const phase = m11DerivePhase(stateTick);
  const regime = m11DeriveRegime(stateTick, macroSchedule);
  const inChaos = m11InChaosWindow(stateTick, chaosWindows);

  const pressureWeight = PRESSURE_WEIGHTS[statePressureTier] ?? 1.0;
  const phaseWeight = PHASE_WEIGHTS[phase] ?? 1.0;
  const regimeWeight = REGIME_WEIGHTS[regime] ?? 1.0;

  const weightedPool = buildWeightedPool(seed + ':pool', pressureWeight * phaseWeight, regimeWeight);
  const poolPick = weightedPool[seededIndex(seed, stateTick + 7, Math.max(1, weightedPool.length))] ?? DEFAULT_CARD;

  const oppPick = OPPORTUNITY_POOL[seededIndex(seed, stateTick + 17, OPPORTUNITY_POOL.length)] ?? DEFAULT_CARD;
  const shuffledDeck = seededShuffle(DEFAULT_CARD_IDS, seed);

  const decayRate = computeDecayRate(regime, M11_BOUNDS.BASE_DECAY_RATE);
  const exitPulse = EXIT_PULSE_MULTIPLIERS[regime] ?? 1.0;
  const regimeMultiplier = REGIME_MULTIPLIERS[regime] ?? 1.0;

  // Core mechanic: inertia tax after threshold.
  const taxApplied = stateMissedOpportunityCount >= M11_BOUNDS.TRIGGER_THRESHOLD;
  const excessCount = Math.max(0, stateMissedOpportunityCount - M11_BOUNDS.TRIGGER_THRESHOLD);

  const taxAmountRaw = taxApplied
    ? M11_BOUNDS.BASE_AMOUNT * Math.pow(M11_BOUNDS.MULTIPLIER, excessCount)
    : 0;

  const taxAmount = taxApplied ? clamp(taxAmountRaw, 0, M11_BOUNDS.MAX_AMOUNT) : 0;

  // Event contracts (must match ./types)
  const streakBrokenEvent: StreakEvent | null = taxApplied
    ? { streakLength: stateMissedOpportunityCount, taxApplied: true }
    : null;

  emit({
    event: 'OPPORTUNITY_MISSED',
    mechanic_id: 'M11',
    tick: stateTick,
    runId: '',
    payload: {
      stateMissedOpportunityCount,
      pressureTier: statePressureTier,
      phase,
      regime,
      inChaos,
      seed,
      // keep shared imports observable
      deckTop: shuffledDeck[0] ?? '',
      oppPick: { id: oppPick.id, name: oppPick.name },
      poolPick: { id: poolPick.id, name: poolPick.name },
      decayRate,
      exitPulse,
      regimeMultiplier,
    },
  });

  emit({
    event: 'INERTIA_TAX_APPLIED',
    mechanic_id: 'M11',
    tick: stateTick,
    runId: '',
    payload: {
      stateMissedOpportunityCount,
      taxApplied,
      excessCount,
      taxAmount,
      bounds: {
        base: M11_BOUNDS.BASE_AMOUNT,
        threshold: M11_BOUNDS.TRIGGER_THRESHOLD,
        multiplier: M11_BOUNDS.MULTIPLIER,
        cap: M11_BOUNDS.MAX_AMOUNT,
      },
    },
  });

  if (taxApplied) {
    emit({
      event: 'PASS_PENALIZED',
      mechanic_id: 'M11',
      tick: stateTick,
      runId: '',
      payload: {
        passPenaltyAmount: taxAmount,
        note: 'passCountUpdated uses the same numeric channel as inertiaTaxAmount for downstream reducers.',
      },
    });

    emit({
      event: 'STREAK_BROKEN',
      mechanic_id: 'M11',
      tick: stateTick,
      runId: '',
      payload: {
        streakBrokenEvent,
      },
    });
  }

  return {
    inertiaTaxAmount: taxAmount,
    streakBrokenEvent,
    passCountUpdated: taxApplied ? taxAmount : 0,
  };
}

